d>
  <!-- Plotly.js -->
  <script src="https://cdn.plot.ly/plotly-latest.min.js"></script>
</head>

<p>
  Enkel <a href="https://bit.ly/1Or9igj">plotly.js</a> demo
</p>
<div id="myDiv"></div>
<script>
    var trace1 = {
        x: [1, 2, 3, 4],
        y: [10, 11, 12, 13],
        text: ['A<br>størrelse: 40', 'B<br>størrelse: 60', 'C<br>størrelse: 80', 'D<br>størrelse: 100'],
        mode: 'markers',
        marker: {
          size: [400, 600, 800, 1000],
          sizemode: 'area'
        }
      };

      var trace2 = {
        x: [1, 2, 3, 4],
        y: [14, 15, 16, 17],
        text: ['A</br>størrelse: 40</br>sixeref: 0.2', 'B</br>størrelse: 60</br>sixeref: 0.2', 'C</br>størrelse: 80</br>sixeref: 0.2', 'D</br>størrelse: 100</br>sixeref: 0.2'],
        mode: 'markers',
        marker: {
          size: [400, 600, 800, 1000],
          // Å sette 'sizeref' lavere enn 1 minsker den viste størrelsen
          sizeref: 2,
          sizemode: 'area'
        }
      };

      var trace3 = {
        x: [1, 2, 3, 4],
        y: [20, 21, 22, 23],
        text: ['A</br>størrelse: 40</br>sixeref: 2', 'B</br>størrelse: 60</br>sixeref: 2', 'C</br>størrelse: 80</br>sixeref: 2', 'D</br>størrelse: 100</br>sixeref: 2'],
        mode: 'markers',
        marker: {
          size: [400, 600, 800, 1000],
          // Å sette 'sizeref' til mindre enn 1 øker den viste marker-størrelsen
          sizeref: 0.2,
          sizemode: 'area'
        }
      };

      // Beregn korrekt 'sizeref' med formelen ovenfor
      var desired_maximum_marker_size = 40;
      var size = [400, 600, 800, 1000];
      var trace4 = {
        x: [1, 2, 3, 4],
        y: [26, 27, 28, 29],
        text: ['A</br>størrelse: 40</br>sixeref: 1.25', 'B</br>størrelse: 60</br>sixeref: 1.25', 'C</br>størrelse: 80</br>sixeref: 1.25', 'D</br>størrelse: 100</br>sixeref: 1.25'],
        mode: 'markers',
        marker: {
          size: size,
          // Kalkuler 'sizeref' med: 2.0 * max(array_of_size_values) / (desired_maximum_marker_size^2)
          sizeref: 2.0 * Math.max(...size) / (desired_maximum_marker_size**2),
          sizemode: 'area'
        }
      };

      var data = [trace1, trace2, trace3, trace4];

      var layout = {
        title: {
          text: 'Størrelsesjustering i boblediagrammer'
        },
        showlegend: false,
        height: 600,
        width: 1200,
        paper_bgcolor: 'rgba(0,0,0,0)',
        plot_bgcolor: 'rgba(0,0,0,0)'
      };

      Plotly.newPlot('myDiv', data, layout);
</script>
